class Solution {
    public String reverseStr(String s, int k) {
        int start = 0;
        int end = s.length() - 1;
        while (end - start >= k) {
            swap(s, start, end);
            start += k;
            end -= k;
        }
        return s;
    }

    void swap(String s, int i, int j) {
        char temp = s.charAt(i);
        s.setCharAt(i, s.charAt(j));
        s.setCharAt(j, temp);
    }
}
```

